#!/bin/bash

# Simple blue square favicon as data URI
FAVICON_DATA='data:image/svg+xml;base64,'

cd src

for file in *.html; do
    echo "Updating $file"
    # Replace favicon.ico with data URI
    sed -i '' "s|href=\"/assets/favicon.ico\"|href=\"$FAVICON_DATA\"|g" "$file"
done

echo "Favicon updates complete!"